INSERT INTO student (korisnik_id, broj_indeksa, studijski_program_id, godina_upisa) SELECT k.id, 'RI 001/25', 1, 2025 FROM korisnik k WHERE k.email = 'student001@ftn.rs' AND NOT EXISTS (SELECT 1 FROM student s WHERE s.korisnik_id = k.id);
INSERT INTO ocena (student_id, ispitni_termin_id, poeni, vrednost_ocene) SELECT s_doc.id, o.ispitni_termin_id, o.poeni, o.vrednost_ocene FROM ocena o JOIN student s_src ON s_src.id = (   SELECT s.id FROM student s   JOIN korisnik k ON k.id = s.korisnik_id   WHERE k.email = 'naisademo_ri_2025_001@ftn.rs' LIMIT 1 ) JOIN student s_doc ON s_doc.korisnik_id = (   SELECT id FROM korisnik WHERE email = 'student001@ftn.rs' LIMIT 1 ) WHERE o.student_id = s_src.id AND NOT EXISTS (   SELECT 1 FROM ocena ex   WHERE ex.student_id = s_doc.id AND ex.ispitni_termin_id = o.ispitni_termin_id );
